IF DB_ID('StudentManagement') IS NULL
    CREATE DATABASE StudentManagement;
GO

USE StudentManagement;
GO

IF OBJECT_ID('dbo.Students', 'U') IS NULL
BEGIN
    CREATE TABLE dbo.Students (
        StudentID NVARCHAR(20) NOT NULL PRIMARY KEY,
        Name NVARCHAR(100) NOT NULL,
        Gender NVARCHAR(20) NULL,
        DOB DATE NULL,
        ClassID NVARCHAR(20) NULL,
        Email NVARCHAR(100) NULL,
        Phone NVARCHAR(20) NULL,
        Status NVARCHAR(30) NULL,
        Major NVARCHAR(100) NULL,
        Username NVARCHAR(50) NULL,
        [Password] NVARCHAR(100) NULL,
        GPA FLOAT NOT NULL CONSTRAINT DF_Students_GPA DEFAULT 0,
        TuitionOwed FLOAT NOT NULL CONSTRAINT DF_Students_TuitionOwed DEFAULT 0
    );
END;
GO

IF COL_LENGTH('dbo.Students', 'Gender') IS NULL
    ALTER TABLE dbo.Students ADD Gender NVARCHAR(20) NULL;
GO

IF COL_LENGTH('dbo.Students', 'DOB') IS NULL
    ALTER TABLE dbo.Students ADD DOB DATE NULL;
GO

IF COL_LENGTH('dbo.Students', 'ClassID') IS NULL
    ALTER TABLE dbo.Students ADD ClassID NVARCHAR(20) NULL;
GO

IF COL_LENGTH('dbo.Students', 'Email') IS NULL
    ALTER TABLE dbo.Students ADD Email NVARCHAR(100) NULL;
GO

IF COL_LENGTH('dbo.Students', 'Phone') IS NULL
    ALTER TABLE dbo.Students ADD Phone NVARCHAR(20) NULL;
GO

IF COL_LENGTH('dbo.Students', 'Status') IS NULL
    ALTER TABLE dbo.Students ADD Status NVARCHAR(30) NULL;
GO

IF COL_LENGTH('dbo.Students', 'Major') IS NULL
    ALTER TABLE dbo.Students ADD Major NVARCHAR(100) NULL;
GO

IF COL_LENGTH('dbo.Students', 'Username') IS NULL
    ALTER TABLE dbo.Students ADD Username NVARCHAR(50) NULL;
GO

IF COL_LENGTH('dbo.Students', 'Password') IS NULL
    ALTER TABLE dbo.Students ADD [Password] NVARCHAR(100) NULL;
GO

IF COL_LENGTH('dbo.Students', 'GPA') IS NULL
    ALTER TABLE dbo.Students ADD GPA FLOAT NOT NULL CONSTRAINT DF_Students_GPA_Auto DEFAULT 0;
GO

IF COL_LENGTH('dbo.Students', 'TuitionOwed') IS NULL
    ALTER TABLE dbo.Students ADD TuitionOwed FLOAT NOT NULL CONSTRAINT DF_Students_TuitionOwed_Auto DEFAULT 0;
GO

IF OBJECT_ID('tempdb..#StudentSeed') IS NOT NULL DROP TABLE #StudentSeed;
CREATE TABLE #StudentSeed (
    StudentID NVARCHAR(20) NOT NULL PRIMARY KEY,
    Name NVARCHAR(100) NOT NULL,
    Gender NVARCHAR(20) NULL,
    DOB DATE NULL,
    ClassID NVARCHAR(20) NULL,
    Email NVARCHAR(100) NULL,
    Phone NVARCHAR(20) NULL,
    Status NVARCHAR(30) NULL,
    Major NVARCHAR(100) NULL,
    Username NVARCHAR(50) NULL,
    [Password] NVARCHAR(100) NULL,
    GPA FLOAT NOT NULL,
    TuitionOwed FLOAT NOT NULL
);











MERGE dbo.Students AS target
USING #StudentSeed AS source
ON target.StudentID = source.StudentID
WHEN MATCHED THEN UPDATE SET
    Name = source.Name,
    Gender = source.Gender,
    DOB = source.DOB,
    ClassID = source.ClassID,
    Email = source.Email,
    Phone = source.Phone,
    Status = source.Status,
    Major = source.Major,
    Username = source.Username,
    [Password] = source.[Password],
    GPA = source.GPA,
    TuitionOwed = source.TuitionOwed
WHEN NOT MATCHED THEN
    INSERT (StudentID,Name,Gender,DOB,ClassID,Email,Phone,Status,Major,Username,[Password],GPA,TuitionOwed)
    VALUES (source.StudentID,source.Name,source.Gender,source.DOB,source.ClassID,source.Email,source.Phone,source.Status,source.Major,source.Username,source.[Password],source.GPA,source.TuitionOwed);
GO

SELECT 'CSV student data is ready.' AS Result;
SELECT COUNT(*) AS TotalStudentsFromCsv FROM dbo.Students WHERE StudentID LIKE 'SV[0-9][0-9][0-9][0-9][0-9]';
SELECT Major, COUNT(*) AS StudentCount FROM dbo.Students WHERE StudentID LIKE 'SV[0-9][0-9][0-9][0-9][0-9]' GROUP BY Major ORDER BY Major;
SELECT StudentID, Name, Major FROM dbo.Students WHERE StudentID LIKE 'SV[0-9][0-9][0-9][0-9][0-9]' ORDER BY StudentID;

/* Contact data from sinhvien_5000_lienhe.csv */
USE StudentManagement;
GO

IF OBJECT_ID('dbo.Students', 'U') IS NULL
BEGIN
    RAISERROR('Table dbo.Students does not exist. Run student_from_csv.sql first.', 16, 1);
    RETURN;
END;
GO

IF COL_LENGTH('dbo.Students', 'Phone') IS NULL
    ALTER TABLE dbo.Students ADD Phone NVARCHAR(20) NULL;
GO

IF COL_LENGTH('dbo.Students', 'Email') IS NULL
    ALTER TABLE dbo.Students ADD Email NVARCHAR(100) NULL;
GO

IF OBJECT_ID('tempdb..#StudentContacts') IS NOT NULL DROP TABLE #StudentContacts;
CREATE TABLE #StudentContacts (
    StudentID NVARCHAR(20) NOT NULL PRIMARY KEY,
    Phone NVARCHAR(20) NULL,
    Email NVARCHAR(100) NULL
);


UPDATE S
SET
    S.Phone = C.Phone,
    S.Email = C.Email
FROM dbo.Students S
INNER JOIN #StudentContacts C ON C.StudentID = S.StudentID;
GO

SELECT 'Student contact data is ready.' AS Result;
SELECT COUNT(*) AS UpdatedStudents
FROM dbo.Students
WHERE StudentID LIKE 'SV[0-9][0-9][0-9][0-9][0-9]' AND Phone IS NOT NULL AND Email IS NOT NULL;

SELECT StudentID, Name, Major, Phone, Email
FROM dbo.Students
WHERE StudentID LIKE 'SV[0-9][0-9][0-9][0-9][0-9]'
ORDER BY StudentID;

SELECT COUNT(*) AS TotalTeachers
FROM dbo.Students;
